        else:
            header_patterns.append(pat)

    return HeaderFooter(
        header_patterns=header_patterns,
        footer_patterns=footer_patterns,
        page_number_pattern=r"^\s*Page\s+\d+\s+of\s+\d+\s*$",
    )

